import { Column, Entity, Index, PrimaryGeneratedColumn } from "typeorm";

@Entity()
export class ListEventOutbox {
  constructor(props?: Partial<ListEventOutbox>) {
    Object.assign(this, props);
  }

  // bigserial — generated by Postgres on insert; TypeORM serialises bigint columns as strings
  @PrimaryGeneratedColumn({ type: "bigint" })
  id!: string;

  @Column("varchar", { length: 36, nullable: false })
  transferId!: string;

  @Column("text", { nullable: false })
  fromAddress!: string;

  @Column("text", { nullable: false })
  toAddress!: string;

  @Column("varchar", { length: 36, nullable: false })
  collectionId!: string;

  @Column("text", { nullable: false })
  tokenId!: string;

  @Column("timestamp with time zone", { nullable: false })
  timestamp!: Date;

  @Index()
  @Column("timestamp with time zone", {
    nullable: false,
    default: () => "now()",
  })
  createdAt!: Date;
}
